// src/config.ts
import { readFileSync as readFileSync2, existsSync as existsSync2 } from "fs";
import { join as join2 } from "path";
import { homedir } from "os";
var DEFAULT_CONFIG = {
  embeddingModel: "nomic-embed-text",
  summarizerModel: "llama3.2",
  retention: { staleHours: 24, supersededDays: 7 },
  walkers: {
    embeddingIdleMs: 5000,
    embeddingBatchSize: 32,
    summarizerIdleMs: 30000,
    summarizerSubtreeThreshold: 25,
    dedupeIntervalMs: 60000,
    stalenessIntervalMs: 30000,
    prunerIntervalMs: 300000
  },
  capture: { maxBytes: 1e5, filterMinSize: 50 },
  trustedExecution: false,
  backend: { kind: "sqlite" }
};
function readJson(path4) {
  try {
    return JSON.parse(readFileSync2(path4, "utf8"));
  } catch {
    return {};
  }
}
function deepMergeConfig(base, override) {
  const result = { ...base };
  for (const key of Object.keys(override)) {
    const val = override[key];
    if (val === undefined)
      continue;
    const baseVal = base[key];
    if (val !== null && typeof val === "object" && !Array.isArray(val) && baseVal !== null && typeof baseVal === "object" && !Array.isArray(baseVal)) {
      result[key] = { ...baseVal, ...val };
    } else {
      result[key] = val;
    }
  }
  return result;
}
function loadConfig(projectRoot) {
  const globalPath = join2(process.env.HOME ?? homedir(), ".ctx-tree", "config.json");
  const globalOverride = existsSync2(globalPath) ? readJson(globalPath) : {};
  const projectPath = projectRoot ? join2(projectRoot, ".ctx-tree", "config.json") : null;
  const projectOverride = projectPath && existsSync2(projectPath) ? readJson(projectPath) : {};
  let merged = deepMergeConfig(deepMergeConfig(DEFAULT_CONFIG, globalOverride), projectOverride);
  if (process.env.CTX_TREE_BACKEND) {
    merged = {
      ...merged,
      backend: { ...merged.backend, kind: process.env.CTX_TREE_BACKEND }
    };
  }
  if (process.env.CTX_TREE_SCHEMA_PATH) {
    merged = {
      ...merged,
      backend: { ...merged.backend, schemaPath: process.env.CTX_TREE_SCHEMA_PATH }
    };
  }
  return merged;
}

// src/project-hash.ts
import { execSync } from "child_process";
import { createHash } from "crypto";
import { readFileSync as readFileSync3, writeFileSync, renameSync, mkdirSync as mkdirSync4 } from "fs";
import { join as join3 } from "path";
import { homedir as homedir2 } from "os";
function computeProjectHash(cwd) {
  try {
    const gitRoot = execSync("git rev-parse --show-toplevel", {
      cwd,
      stdio: ["pipe", "pipe", "pipe"]
    }).toString().trim();
    const firstCommit = execSync("git rev-list --max-parents=0 HEAD", {
      cwd,
      stdio: ["pipe", "pipe", "pipe"]
    }).toString().trim();
    return createHash("sha256").update(`${gitRoot}:${firstCommit}`).digest("hex").slice(0, 16);
  } catch {
    return createHash("sha256").update(cwd).digest("hex").slice(0, 16);
  }
}
function getProjectsTsvPath() {
  const ctxTreeHome = process.env.CTX_TREE_HOME ?? join3(homedir2(), ".ctx-tree");
  return join3(ctxTreeHome, "projects.tsv");
}
function readEntries() {
  const PROJECTS_TSV = getProjectsTsvPath();
  try {
    const content = readFileSync3(PROJECTS_TSV, "utf-8");
    return content.split(`
`).filter((line) => line.trim()).map((line) => {
      const [cwd, hash] = line.split("\t");
      return [cwd, hash];
    });
  } catch (err2) {
    if (err2.code === "ENOENT")
      return [];
    throw err2;
  }
}
function writeEntries(entries) {
  const PROJECTS_TSV = getProjectsTsvPath();
  const ctxTreeHome = process.env.CTX_TREE_HOME ?? join3(homedir2(), ".ctx-tree");
  try {
    mkdirSync4(ctxTreeHome, { recursive: true, mode: 448 });
  } catch {}
  const tmpPath = `${PROJECTS_TSV}.tmp.${process.pid}`;
  const content = entries.map(([cwd, hash]) => `${cwd}	${hash}`).join(`
`);
  const finalContent = entries.length > 0 ? content + `
` : "";
  writeFileSync(tmpPath, finalContent, "utf-8");
  renameSync(tmpPath, PROJECTS_TSV);
}
function registerProject(cwd, hash) {
  const entries = readEntries();
  const existingIndex = entries.findIndex(([cwdEntry]) => cwdEntry === cwd);
  if (existingIndex >= 0) {
    entries[existingIndex] = [cwd, hash];
  } else {
    entries.push([cwd, hash]);
  }
  writeEntries(entries);
}
function deregisterProject(hash) {
  const entries = readEntries();
  const filtered = entries.filter(([, hashEntry]) => hashEntry !== hash);
  writeEntries(filtered);
}

// src/walkers/filter.ts
var BATCH_SIZE = 50;
async function runFilterWalker(store, config2) {
  const pending = await store.getPendingNodes(BATCH_SIZE);
  if (pending.length === 0)
    return;
  const decisions = [];
  for (const node of pending) {
    if (node.original_bytes < config2.capture.filterMinSize) {
      decisions.push({ id: node.id, action: "prune" });
      continue;
    }
    const existing = await store.getNodeByContentHash(node.content_hash);
    if (existing && existing.id !== node.id && existing.status === "live") {
      decisions.push({ id: node.id, action: "prune" });
      continue;
    }
    decisions.push({ id: node.id, action: "promote" });
  }
  await store.atomicBatchFilter(decisions);
}

// src/walkers/staleness.ts
import { statSync } from "fs";
async function runStalenessWalker(store, _config) {
  const checkBefore = Date.now() - 5000;
  const chunks = await store.getLiveFileChunks(checkBefore);
  for (const node of chunks) {
    const meta2 = JSON.parse(node.metadata);
    const filePath = meta2.filePath ?? node.source_uri?.replace(/^file:\/\//, "").split("#")[0];
    if (!filePath)
      continue;
    try {
      const stat = statSync(filePath);
      if (Math.round(stat.mtimeMs) !== node.mtime) {
        await store.updateNodeStatus(node.id, "stale");
      }
    } catch {
      await store.updateNodeStatus(node.id, "stale");
    }
  }
}

// src/walkers/pruner.ts
async function runPrunerWalker(store, config2) {
  const now = Date.now();
  const staleThreshold = now - config2.retention.staleHours * 60 * 60 * 1000;
  const supersededThreshold = now - config2.retention.supersededDays * 24 * 60 * 60 * 1000;
  for (const node of await store.getStaleNodes(staleThreshold)) {
    await store.pruneNode(node.id);
  }
  for (const node of await store.getSupersededNodes(supersededThreshold)) {
    await store.pruneNode(node.id);
  }
}

// src/walkers/embedding.ts
var inFlight = false;
function runEmbeddingWalker(store, config2, provider) {
  if (!provider)
    return;
  if (inFlight)
    return;
  inFlight = true;
  const batchSize = config2.walkers.embeddingBatchSize;
  store.getPendingEmbeddingNodes(batchSize).then((rows) => {
    if (rows.length === 0)
      return;
    const texts = rows.map((r2) => r2.content);
    return provider.embed(texts).then((vectors) => {
      const now = Date.now();
      const upsertRows = rows.map((row, i3) => ({
        id: row.id,
        embedding: Buffer.from(new Float32Array(vectors[i3]).buffer),
        model: provider.model,
        dim: vectors[i3].length,
        embeddedAt: now
      }));
      return store.batchUpsertNodeVec(upsertRows);
    });
  }).catch((e2) => {
    process.stderr.write(`ctx-tree embedding error: ${e2}
`);
  }).finally(() => {
    inFlight = false;
  });
}

// src/walkers/summarizer.ts
var CHAR_THRESHOLD_MULTIPLIER = 20;
var inFlight2 = false;
function runSummarizerWalker(store, config2, provider) {
  if (!provider)
    return;
  if (inFlight2)
    return;
  const charThreshold = Math.max(500, config2.walkers.summarizerSubtreeThreshold * CHAR_THRESHOLD_MULTIPLIER);
  const batchSize = 10;
  inFlight2 = true;
  store.getNodesNeedingSummarization(charThreshold, batchSize).then((rows) => {
    if (rows.length === 0) {
      return Promise.resolve();
    }
    const promises = rows.map((row) => provider.summarize(row.content, row.source_uri ?? undefined).then((summary) => store.updateNodeSummary(row.id, summary)).catch((e2) => {
      process.stderr.write(`ctx-tree summarizer error: ${e2}
`);
    }));
    return Promise.all(promises);
  }).catch((e2) => {
    process.stderr.write(`ctx-tree summarizer error: ${e2}
`);
  }).finally(() => {
    inFlight2 = false;
  });
}

// src/walkers/dedupe.ts
function cosineSimilarity(a2, b4) {
  if (a2.length !== b4.length)
    return 0;
  let dot = 0, normA = 0, normB = 0;
  for (let i3 = 0;i3 < a2.length; i3++) {
    dot += a2[i3] * b4[i3];
    normA += a2[i3] * a2[i3];
    normB += b4[i3] * b4[i3];
  }
  const denom = Math.sqrt(normA) * Math.sqrt(normB);
  if (!isFinite(denom) || denom === 0)
    return 0;
  return dot / denom;
}
async function runDedupeWalker(store, _config) {
  const pairs = await store.getDedupeCandidatePairs();
  if (pairs.length === 0)
    return;
  const now = Date.now();
  for (const pair of pairs) {
    const a2 = new Float32Array(pair.emb1.buffer, pair.emb1.byteOffset, pair.emb1.byteLength / 4);
    const b4 = new Float32Array(pair.emb2.buffer, pair.emb2.byteOffset, pair.emb2.byteLength / 4);
    const sim = cosineSimilarity(a2, b4);
    if (sim > 0.95) {
      const keepId = pair.ts1 >= pair.ts2 ? pair.id1 : pair.id2;
      const pruneId = pair.ts1 >= pair.ts2 ? pair.id2 : pair.id1;
      await store.atomicPruneAndSupersede(pruneId, keepId, now);
    }
  }
}

// src/walkers/coordinator.ts
function withErrorBoundary(name2, fn2) {
  try {
    const result = fn2();
    if (result instanceof Promise) {
      result.catch((e2) => {
        process.stderr.write(`ctx-tree ${name2} error: ${e2}
`);
      });
    }
  } catch (e2) {
    process.stderr.write(`ctx-tree ${name2} error: ${e2}
`);
  }
}

class WalkerCoordinator {
  timers = [];
  async startupSweep(store, config2) {
    let swept = 0;
    while (true) {
      const before = await store.countPendingNodes();
      if (before === 0)
        break;
      await runFilterWalker(store, config2);
      swept++;
      if (swept > 1000)
        break;
    }
    if (swept > 0)
      process.stderr.write(`ctx-tree: startup sweep processed pending rows in ${swept} passes
`);
  }
  start(store, config2, embedding, summarizer) {
    this.startupSweep(store, config2).catch((e2) => {
      process.stderr.write(`ctx-tree startup-sweep error: ${e2}
`);
    });
    this.timers.push(setInterval(() => withErrorBoundary("filter", () => runFilterWalker(store, config2)), 500), setInterval(() => withErrorBoundary("staleness", () => runStalenessWalker(store, config2)), config2.walkers.stalenessIntervalMs), setInterval(() => withErrorBoundary("pruner", () => runPrunerWalker(store, config2)), config2.walkers.prunerIntervalMs));
    if (embedding) {
      this.timers.push(setInterval(() => withErrorBoundary("embedding", () => runEmbeddingWalker(store, config2, embedding)), config2.walkers.embeddingIdleMs));
    }
    if (summarizer) {
      this.timers.push(setInterval(() => withErrorBoundary("summarizer", () => runSummarizerWalker(store, config2, summarizer)), config2.walkers.summarizerIdleMs));
    }
    if (config2.walkers.dedupeIntervalMs > 0) {
      this.timers.push(setInterval(() => withErrorBoundary("dedupe", () => runDedupeWalker(store, config2)), config2.walkers.dedupeIntervalMs));
    }
  }
  stop() {
    this.timers.forEach((t) => clearInterval(t));
    this.timers = [];
  }
}

// src/tools/search.ts
async function searchKeyword(store, query, limit = 20, filters = {}) {
  const nodes = await store.searchKeyword(query, filters, limit);
  return { nodes };
}
async function searchSemantic(store, config2, provider, query, limit = 20, filters = {}) {
  if (!query.trim())
    return { nodes: [] };
  if (!provider) {
    throw new McpError(ErrorCode.InvalidParams, "semantic search requires an embedding provider");
  }
  const [queryVec] = await provider.embed([query]);
  const nodes = await store.searchSemantic(queryVec, provider.model, filters, limit);
  return { nodes };
}
async function searchHybrid(store, config2, provider, query, limit = 20, filters = {}) {
  if (!query.trim())
    return { nodes: [] };
  if (!provider) {
    throw new McpError(ErrorCode.InvalidParams, "hybrid search requires an embedding provider");
  }
  const keywordResults = (await searchKeyword(store, query, limit * 2, filters)).nodes;
  const semanticResults = (await searchSemantic(store, config2, provider, query, limit * 2, filters)).nodes;
  const RRF_K = 60;
  const scores = new Map;
  keywordResults.forEach((n4, i3) => scores.set(n4.id, (scores.get(n4.id) ?? 0) + 1 / (RRF_K + i3 + 1)));
  semanticResults.forEach((n4, i3) => scores.set(n4.id, (scores.get(n4.id) ?? 0) + 1 / (RRF_K + i3 + 1)));
  const allNodes = new Map;
  for (const n4 of [...keywordResults, ...semanticResults])
    allNodes.set(n4.id, n4);
  const sorted = [...allNodes.values()].sort((a2, b4) => (scores.get(b4.id) ?? 0) - (scores.get(a2.id) ?? 0));
  return { nodes: sorted.slice(0, limit) };
}

