import { createHash as createHash4 } from "crypto";
function extractTitle(html) {
  const m4 = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
  return m4 ? decodeEntities(stripTags(m4[1])).trim() : "";
}
function extractMeta(html, name2) {
  const byName = html.match(new RegExp(`<meta[^>]+name=["']${name2}["'][^>]+content=["']([^"']*?)["']`, "i")) ?? html.match(new RegExp(`<meta[^>]+content=["']([^"']*?)["'][^>]+name=["']${name2}["']`, "i"));
  if (byName)
    return byName[1].trim();
  const og = html.match(/<meta[^>]+property=["']og:description["'][^>]+content=["']([^"']*?)["']/i) ?? html.match(/<meta[^>]+content=["']([^"']*?)["'][^>]+property=["']og:description["']/i);
  return og ? og[1].trim() : "";
}
function extractHeadings(html) {
  const re3 = /<h([1-3])[^>]*>([\s\S]*?)<\/h\1>/gi;
  const headings = [];
  let m4;
  while ((m4 = re3.exec(html)) !== null && headings.length < 12) {
    const text = decodeEntities(stripTags(m4[2])).trim();
    if (text)
      headings.push(text);
  }
  return headings;
}
function extractBodyText(html) {
  const cleaned = html.replace(/<script[\s\S]*?<\/script>/gi, "").replace(/<style[\s\S]*?<\/style>/gi, "").replace(/<nav[\s\S]*?<\/nav>/gi, "").replace(/<footer[\s\S]*?<\/footer>/gi, "").replace(/<header[\s\S]*?<\/header>/gi, "").replace(/<aside[\s\S]*?<\/aside>/gi, "").replace(/<noscript[\s\S]*?<\/noscript>/gi, "");
  const main = cleaned.match(/<(?:main|article)[^>]*>([\s\S]*?)<\/(?:main|article)>/i)?.[1] ?? cleaned;
  return decodeEntities(stripTags(main)).replace(/\n{3,}/g, `

`).replace(/[ \t]{2,}/g, " ").trim();
}
function stripTags(s4) {
  return s4.replace(/<[^>]+>/g, " ").replace(/\s+/g, " ");
}
function decodeEntities(s4) {
  return s4.replace(/&amp;/g, "&").replace(/&lt;/g, "<").replace(/&gt;/g, ">").replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&nbsp;/g, " ").replace(/&#(\d+);/g, (_3, n4) => String.fromCharCode(Number(n4)));
}
function estimateTokens3(text) {
  return Math.ceil(text.length / 4);
}
var CACHE_TTL_MS = 60 * 60 * 1000;
async function ctxTreeBrowse(store, _config, params) {
  const { url, budget_tokens = 2000, force = false } = params;
  if (!url || typeof url !== "string") {
    throw new McpError(ErrorCode.InvalidParams, '"url" is required and must be a string');
  }
  let parsedUrl;
  try {
    parsedUrl = new URL(url);
  } catch {
    throw new McpError(ErrorCode.InvalidParams, `Invalid URL: ${url}`);
  }
  if (!["http:", "https:"].includes(parsedUrl.protocol)) {
    throw new McpError(ErrorCode.InvalidParams, `Only http/https URLs are supported`);
  }
  if (!force) {
    const cached2 = await store.getNodeBySourceUri(url);
    if (cached2 && Date.now() - cached2.updated_at < CACHE_TTL_MS) {
      const meta2 = JSON.parse(cached2.metadata);
      const bodyText2 = budgetContent(cached2.content, budget_tokens);
      return {
        nodeId: cached2.id,
        url,
        title: meta2.title ?? "",
        description: meta2.description ?? "",
        headings: meta2.headings ?? [],
        content: bodyText2.text,
        truncated: bodyText2.truncated,
        cached: true
      };
    }
  }
  let html;
  let fetchedBytes;
  try {
    const res = await fetch(url, {
      headers: { "User-Agent": "ctx-tree/1.0 (https://github.com/joeblackwaslike/ctx-tree)" },
      signal: AbortSignal.timeout(15000)
    });
    if (!res.ok) {
      throw new McpError(ErrorCode.InvalidParams, `HTTP ${res.status} fetching ${url}`);
    }
    html = await res.text();
    fetchedBytes = Buffer.byteLength(html, "utf8");
  } catch (err2) {
    if (err2 instanceof McpError)
      throw err2;
    throw new McpError(ErrorCode.InternalError, `Failed to fetch ${url}: ${err2.message}`);
  }
  const title = extractTitle(html);
  const description = extractMeta(html, "description");
  const headings = extractHeadings(html);
  const bodyText = extractBodyText(html);
  const { text: content, truncated } = budgetContent(bodyText, budget_tokens);
  const contentHash = createHash4("sha256").update(bodyText).digest("hex");
  const existing = await store.getNodeBySourceUri(url);
  if (existing) {
    if (existing.content_hash === contentHash) {
      return { nodeId: existing.id, url, title, description, headings, content, truncated, cached: true };
    }
    await store.updateNodeStatus(existing.id, "stale");
  }
  const nodeId = ulid2();
  await store.insertNode(nodeId, {
    parent_id: null,
    kind: "web_chunk",
    source_uri: url,
    content: bodyText,
    content_hash: contentHash,
    status: "live",
    mtime: Date.now(),
    truncated: truncated ? 1 : 0,
    original_bytes: fetchedBytes,
    metadata: JSON.stringify({ url, title, description, headings })
  });
  if (existing) {
    await store.insertEdge({ src_id: nodeId, dst_id: existing.id, kind: "supersedes" });
  }
  return { nodeId, url, title, description, headings, content, truncated, cached: false };
}
function budgetContent(text, budget) {
  if (estimateTokens3(text) <= budget)
    return { text, truncated: false };
  const charBudget = budget * 4;
  return { text: text.slice(0, charBudget), truncated: true };
}

// src/tools/monitor.ts
import { createHash as createHash5 } from "crypto";
var DEFAULT_TIMEOUT_MS = 30000;
var PREVIEW_CHARS = 500;
async function ctxTreeMonitor(store, config2, params) {
  const { command, timeout_ms = DEFAULT_TIMEOUT_MS, cwd } = params;
  if (!command || typeof command !== "string") {
    throw new McpError(ErrorCode.InvalidParams, '"command" is required and must be a string');
  }
  if (!config2.trustedExecution) {
    throw new McpError(ErrorCode.InvalidParams, "ctx_tree_monitor requires trustedExecution: true in config. Set it in your ctx-tree config to enable this tool.");
  }
  const sourceUri = `cmd://${createHash5("sha256").update(command).digest("hex").slice(0, 16)}`;
  let output;
  let exitCode;
  try {
    const proc = Bun.spawn(["sh", "-c", command], {
      cwd: cwd ?? process.cwd(),
      stdout: "pipe",
      stderr: "pipe"
    });
    const timeoutId = setTimeout(() => proc.kill(), timeout_ms);
    const [stdoutBuf, stderrBuf] = await Promise.all([
      new Response(proc.stdout).text(),
      new Response(proc.stderr).text()
    ]);
    exitCode = await proc.exited;
    clearTimeout(timeoutId);
    output = redactBashOutput(stdoutBuf + (stderrBuf ? `
[stderr]
${stderrBuf}` : ""));
  } catch (err2) {
    throw new McpError(ErrorCode.InternalError, `Failed to run command: ${err2.message}`);
  }
  const contentHash = createHash5("sha256").update(output).digest("hex");
  const lines = output.split(`
`);
  const preview = output.slice(-PREVIEW_CHARS);
  const existing = await store.getNodeBySourceUri(sourceUri);
  if (existing) {
    if (existing.content_hash === contentHash) {
      return {
        nodeId: existing.id,
        command,
        exit_code: exitCode,
        lines_captured: lines.length,
        preview,
        cached: true
      };
    }
    await store.updateNodeStatus(existing.id, "stale");
  }
  const nodeId = ulid2();
  await store.insertNode(nodeId, {
    parent_id: null,
    kind: "tool_output",
    source_uri: sourceUri,
    content: output,
    content_hash: contentHash,
    status: "live",
    mtime: Date.now(),
    truncated: 0,
    original_bytes: Buffer.byteLength(output, "utf8"),
    metadata: JSON.stringify({ command, exit_code: exitCode, cwd: cwd ?? process.cwd() })
  });
  if (existing) {
    await store.insertEdge({ src_id: nodeId, dst_id: existing.id, kind: "supersedes" });
  }
  return {
    nodeId,
    command,
    exit_code: exitCode,
    lines_captured: lines.length,
    preview,
    cached: false
  };
}

